-- Static Learning Module seed data generated from the markdown catalog.
-- Source: database/seeds/learning-modules/*/lessons/*.md

\echo 'Seeding published learning modules from markdown catalog...'

BEGIN;

DROP TABLE IF EXISTS seed_learning_module;
DROP TABLE IF EXISTS seed_learning_module_skill;
DROP TABLE IF EXISTS seed_learning_module_lesson;
DROP TABLE IF EXISTS seed_learning_module_quiz;
DROP TABLE IF EXISTS seed_learning_module_quiz_question;
DROP TABLE IF EXISTS seed_learning_module_quiz_option;

CREATE TEMP TABLE seed_learning_module_skill (
    skill_id uuid PRIMARY KEY,
    name text NOT NULL,
    slug text NOT NULL,
    description text NOT NULL,
    category text NOT NULL
) ON COMMIT DROP;

CREATE TEMP TABLE seed_learning_module (
    skill_module_id uuid PRIMARY KEY,
    skill_slug text NOT NULL,
    title text NOT NULL,
    slug text NOT NULL,
    description text NOT NULL,
    difficulty_level text NOT NULL,
    estimated_hours numeric(5,2) NOT NULL,
    metadata_json text NOT NULL
) ON COMMIT DROP;

CREATE TEMP TABLE seed_learning_module_lesson (
    skill_module_lesson_id uuid PRIMARY KEY,
    skill_module_id uuid NOT NULL,
    title text NOT NULL,
    slug text NOT NULL,
    summary text,
    order_index int NOT NULL,
    estimated_hours numeric(5,2) NOT NULL,
    markdown_file_key text NOT NULL,
    markdown_file_name text NOT NULL,
    content_hash text NOT NULL,
    content_size_bytes bigint NOT NULL,
    indexing_status text NOT NULL,
    indexing_error text
) ON COMMIT DROP;

CREATE TEMP TABLE seed_learning_module_quiz (
    skill_module_quiz_id uuid PRIMARY KEY,
    skill_module_id uuid NOT NULL,
    title text NOT NULL,
    description text NOT NULL,
    passing_score_percent numeric(5,2) NOT NULL,
    max_attempts int NOT NULL,
    status text NOT NULL
) ON COMMIT DROP;

CREATE TEMP TABLE seed_learning_module_quiz_question (
    skill_module_quiz_question_id uuid PRIMARY KEY,
    skill_module_id uuid NOT NULL,
    question_text text NOT NULL,
    question_type text NOT NULL,
    explanation text,
    order_index int NOT NULL,
    points int NOT NULL
) ON COMMIT DROP;

CREATE TEMP TABLE seed_learning_module_quiz_option (
    skill_module_quiz_option_id uuid PRIMARY KEY,
    skill_module_quiz_question_id uuid NOT NULL,
    option_text text NOT NULL,
    is_correct boolean NOT NULL,
    explanation text,
    order_index int NOT NULL
) ON COMMIT DROP;







SELECT
    md5(seed.skill_module_id::text || ':readiness-question-' || generated.question_number::text)::uuid,
    seed.skill_module_id,
    format('Which habit best supports completing %s thoughtfully?', seed.title),
    'single_choice',
    'The seeded module expects applied practice and review notes as learning evidence.',
    generated.question_number,
    1
FROM seed_learning_module seed
CROSS JOIN generate_series(3, 10) AS generated(question_number);

SELECT
    md5(question.skill_module_quiz_question_id::text || ':option-' || option_row.order_index::text)::uuid,
    question.skill_module_quiz_question_id,
    option_row.option_text,
    option_row.is_correct,
    option_row.explanation,
    option_row.order_index
FROM seed_learning_module_quiz_question question
CROSS JOIN (
    VALUES
        ('Practice the lesson and capture a short note or artifact.', true, 'Applied evidence is the expected completion signal.', 1),
        ('Only skim the lesson headings.', false, 'Skimming does not demonstrate the module outcome.', 2),
        ('Mark the module complete without checking the lesson content.', false, 'Completion should follow lesson work.', 3)
) AS option_row(option_text, is_correct, explanation, order_index)
WHERE question.order_index BETWEEN 3 AND 10;

    skill_id,
    name,
    slug,
    description,
    category,
    is_active,
    created_at,
    updated_at
)
SELECT
    seed.skill_id,
    seed.name,
    seed.slug,
    seed.description,
    seed.category,
    true,
    now(),
    now()
FROM seed_learning_module_skill seed
ON CONFLICT DO NOTHING;

DO $$
DECLARE
    missing_skills text;
BEGIN
    SELECT string_agg(DISTINCT seed.skill_slug, ', ' ORDER BY seed.skill_slug)
    INTO missing_skills
    FROM seed_learning_module seed
    LEFT JOIN public.skill skill
        ON skill.slug = seed.skill_slug
    WHERE skill.skill_id IS NULL;

    IF missing_skills IS NOT NULL THEN
        RAISE EXCEPTION 'Missing skill slugs required by learning module seed: %', missing_skills;
    END IF;

    IF NOT EXISTS (
        SELECT 1
        FROM public."user"
        WHERE username_normalized = 'contentmanager'
    ) THEN
        RAISE EXCEPTION 'Missing demo content manager user: contentmanager';
    END IF;
END $$;

    skill_module_id,
    skill_id,
    title,
    slug,
    description,
    difficulty_level,
    estimated_hours,
    status,
    created_by_user_id,
    published_at,
    archived_at,
    metadata,
    created_at,
    updated_at
)
SELECT
    seed.skill_module_id,
    skill.skill_id,
    seed.title,
    seed.slug,
    seed.description,
    seed.difficulty_level,
    seed.estimated_hours,
    'published',
    actor.user_id,
    TIMESTAMPTZ '2026-07-04 00:00:00+00',
    NULL,
    seed.metadata_json::jsonb,
    now(),
    now()
FROM seed_learning_module seed
JOIN public.skill skill
    ON skill.slug = seed.skill_slug
CROSS JOIN LATERAL (
    SELECT user_id
    FROM public."user"
    WHERE username_normalized = 'contentmanager'
    LIMIT 1
) actor
ON CONFLICT (skill_module_id) DO UPDATE SET
    skill_id = EXCLUDED.skill_id,
    title = EXCLUDED.title,
    slug = EXCLUDED.slug,
    description = EXCLUDED.description,
    difficulty_level = EXCLUDED.difficulty_level,
    estimated_hours = EXCLUDED.estimated_hours,
    status = EXCLUDED.status,
    created_by_user_id = EXCLUDED.created_by_user_id,
    published_at = EXCLUDED.published_at,
    archived_at = EXCLUDED.archived_at,
    metadata = EXCLUDED.metadata,
    updated_at = now();

    skill_module_lesson_id,
    skill_module_id,
    title,
    slug,
    summary,
    order_index,
    estimated_hours,
    markdown_file_key,
    markdown_file_name,
    content_hash,
    content_size_bytes,
    content_version,
    indexing_status,
    indexed_at,
    indexing_error,
    created_at,
    updated_at
)
SELECT
    seed.skill_module_lesson_id,
    seed.skill_module_id,
    seed.title,
    seed.slug,
    seed.summary,
    seed.order_index,
    seed.estimated_hours,
    seed.markdown_file_key,
    seed.markdown_file_name,
    seed.content_hash,
    seed.content_size_bytes,
    1,
    seed.indexing_status,
    NULL,
    seed.indexing_error,
    now(),
    now()
FROM seed_learning_module_lesson seed
ON CONFLICT (skill_module_lesson_id) DO UPDATE SET
    title = EXCLUDED.title,
    slug = EXCLUDED.slug,
    summary = EXCLUDED.summary,
    order_index = EXCLUDED.order_index,
    estimated_hours = EXCLUDED.estimated_hours,
    markdown_file_key = EXCLUDED.markdown_file_key,
    markdown_file_name = EXCLUDED.markdown_file_name,
    content_hash = EXCLUDED.content_hash,
    content_size_bytes = EXCLUDED.content_size_bytes,
    content_version = EXCLUDED.content_version,
    indexing_status = EXCLUDED.indexing_status,
    indexed_at = EXCLUDED.indexed_at,
    indexing_error = EXCLUDED.indexing_error,
    updated_at = now();

    skill_module_quiz_id,
    skill_module_id,
    title,
    description,
    passing_score_percent,
    max_attempts,
    status,
    created_at,
    updated_at
)
SELECT
    seed.skill_module_quiz_id,
    seed.skill_module_id,
    seed.title,
    seed.description,
    seed.passing_score_percent,
    seed.max_attempts,
    seed.status,
    now(),
    now()
FROM seed_learning_module_quiz seed
ON CONFLICT ON CONSTRAINT uq_skill_module_quiz_module DO UPDATE SET
    title = EXCLUDED.title,
    description = EXCLUDED.description,
    passing_score_percent = EXCLUDED.passing_score_percent,
    max_attempts = EXCLUDED.max_attempts,
    status = EXCLUDED.status,
    updated_at = now();

    skill_module_quiz_question_id,
    skill_module_quiz_id,
    question_text,
    question_type,
    explanation,
    order_index,
    points,
    created_at,
    updated_at
)
SELECT
    seed.skill_module_quiz_question_id,
    quiz.skill_module_quiz_id,
    seed.question_text,
    seed.question_type,
    seed.explanation,
    seed.order_index,
    seed.points,
    now(),
    now()
FROM seed_learning_module_quiz_question seed
JOIN public.skill_module_quiz quiz
    ON quiz.skill_module_id = seed.skill_module_id
ON CONFLICT (skill_module_quiz_question_id) DO UPDATE SET
    skill_module_quiz_id = EXCLUDED.skill_module_quiz_id,
    question_text = EXCLUDED.question_text,
    question_type = EXCLUDED.question_type,
    explanation = EXCLUDED.explanation,
    order_index = EXCLUDED.order_index,
    points = EXCLUDED.points,
    updated_at = now();

    skill_module_quiz_option_id,
    skill_module_quiz_question_id,
    option_text,
    is_correct,
    explanation,
    order_index,
    created_at,
    updated_at
)
SELECT
    seed.skill_module_quiz_option_id,
    seed.skill_module_quiz_question_id,
    seed.option_text,
    seed.is_correct,
    seed.explanation,
    seed.order_index,
    now(),
    now()
FROM seed_learning_module_quiz_option seed
ON CONFLICT (skill_module_quiz_option_id) DO UPDATE SET
    skill_module_quiz_question_id = EXCLUDED.skill_module_quiz_question_id,
    option_text = EXCLUDED.option_text,
    is_correct = EXCLUDED.is_correct,
    explanation = EXCLUDED.explanation,
    order_index = EXCLUDED.order_index,
    updated_at = now();

COMMIT;
